// ============================================================================
// Main Router Factory
// ============================================================================

export interface CreateRoutesOptions {
  /** Prisma client instance */
  prisma?: PrismaClient
  /** Hook configurations */
  hooks?: RouteHooksConfig
  /** Custom routes to add */
  customRoutes?: (router: Hono) => void
}

/**
 * Create all generated routes
 */
export function createGeneratedRoutes(options: CreateRoutesOptions = {}): Hono {
  const router = new Hono()

  // Set Prisma client if provided
  if (options.prisma) {
    setPrisma(options.prisma)
  }

  // Set hooks if provided
  if (options.hooks) {
    setHooks(options.hooks)
  }

  // Mount model routes
  router.route("/workspaces", createWorkspaceRoutes())
  router.route("/projects", createProjectRoutes())
  router.route("/starred-projects", createStarredProjectRoutes())
  router.route("/members", createMemberRoutes())
  router.route("/billing-accounts", createBillingAccountRoutes())
  router.route("/invitations", createInvitationRoutes())
  router.route("/folders", createFolderRoutes())
  router.route("/notifications", createNotificationRoutes())

  // Apply custom routes if provided
  if (options.customRoutes) {
    options.customRoutes(router)
  }

  return router
}

export default createGeneratedRoutes